using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

namespace TicketClassifier.Models;

public class EvaluationResult
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public IReadOnlyList<CategoryMetric> PerCategoryMetrics { get; set; } = [];
}

public class CategoryMetric
{
    public string Category { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly EvaluationResult _evaluationResult;
    private readonly string[] _categoryLabels;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        IDataView dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(dataView);

        // Extract the ordered category labels from the key-value mapping
        var labelColumn = _model.GetOutputSchema(dataView.Schema)["Label"];
        var keyValues = new VBuffer<ReadOnlyMemory<char>>();
        labelColumn.GetKeyValues(ref keyValues);
        _categoryLabels = keyValues.DenseValues().Select(v => v.ToString()).ToArray();

        _evaluationResult = Evaluate(dataView);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);
    }

    private EvaluationResult Evaluate(IDataView dataView)
    {
        IDataView predictions = _model.Transform(dataView);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        var perCategory = metrics.PerClassLogLoss
            .Select((_, i) => new CategoryMetric
            {
                Category = i < _categoryLabels.Length ? _categoryLabels[i] : $"Class {i}",
                Precision = i < metrics.ConfusionMatrix.PerClassPrecision.Count
                    ? metrics.ConfusionMatrix.PerClassPrecision[i] : 0,
                Recall = i < metrics.ConfusionMatrix.PerClassRecall.Count
                    ? metrics.ConfusionMatrix.PerClassRecall[i] : 0,
                F1Score = ComputeF1(
                    i < metrics.ConfusionMatrix.PerClassPrecision.Count
                        ? metrics.ConfusionMatrix.PerClassPrecision[i] : 0,
                    i < metrics.ConfusionMatrix.PerClassRecall.Count
                        ? metrics.ConfusionMatrix.PerClassRecall[i] : 0)
            })
            .ToList();

        return new EvaluationResult
        {
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction,
            PerCategoryMetrics = perCategory
        };
    }

    private static double ComputeF1(double precision, double recall) =>
        precision + recall > 0 ? 2 * precision * recall / (precision + recall) : 0;

    public (string Category, Dictionary<string, float> Confidence) Predict(TicketRequest request)
    {
        var data = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(data);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < _categoryLabels.Length; i++)
        {
            confidence[_categoryLabels[i]] = prediction.Score[i];
        }

        return (prediction.Category, confidence);
    }

    public EvaluationResult GetEvaluationResult() => _evaluationResult;
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketClassifierController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    [HttpPost("predict")]
    public IActionResult Predict([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var (category, confidence) = _classifier.Predict(request);

        return Ok(new
        {
            predictedCategory = category,
            confidence
        });
    }

    [HttpGet("evaluate")]
    public IActionResult Evaluate()
    {
        return Ok(_classifier.GetEvaluationResult());
    }
}

